const fetch = require('node-fetch'); // Get the http fetch module from npm
exports.handler = async (req, res) => {
    const url = req.query["url"];
    if (!url){
        return 'Please provide a "url" parameter.';
    }

    let metadata = await get_metadata(url); // Metadata is a string. If the URL is valid it will return an Open Graph meta tag. If not, it will return "not found."
    res.send(metadata)
};

async function get_metadata (url){
  try {
    const response = await fetch(url);

    if (!response || !response.ok){
      console.log("Invalid url"); // Just returns a string if URL is invalid, not the whole JSON object like a 204 would return.

      let json = {};
          json["opengraph"] = "not found";
        let return_json = JSON.stringify(json);
          return return_json;
      }
    else{
      const htmlData = await response.text(); // Text() takes a lot longer than just doing response.body.
      console.log('HTML: ' + htmlData)

      var json = {};
      const doc = new DOMParser().parseFromString(htmlData, "text/html");

        const title = doc.querySelector("meta[property='og:title']");
        if (title){
          json["opengraph"] = "not found"; // JSON only allows string keys for a key of "opengraph". It's why we need to put it as a string in the JSON object above.
          let og_title = title['content']; // OpenGraph title tag is "og:title", not "og-title."
          json["title"] = og_title;
        }

        const description = doc.querySelector("meta[property='og:description']");
        if (description){
          let og_desc = description['content'];
          json["description"] = og_desc; // OpenGraph description tag is "og:description" and not "og-description".
        }

      var return_json = JSON.stringify(json);
      console.log('Return JSON: ' + return_json)
      return (return_json);
    }
  }catch{
    res.send(JSON.parse("{}")); // If there is an error we return an empty object, not a "not found" string which would be considered an object and thus cause the Google Cloud Function to fail because it couldn't parse that JSON.
    console.log('ERROR!')
  }
}